import { useState, useEffect } from "react";

import {
  AppBar,
  Toolbar,
  Typography,
  Box,
  Button,
  Container,
  Paper,
  TextField,
  MenuItem,
} from "@mui/material";

import { useNavigate } from "react-router-dom";

import "./CreatePage.css";

function CreatePage() {

  const navigate = useNavigate();

  // =========================
  // 로그인 보호
  // =========================
  useEffect(() => {

    const token = localStorage.getItem("token");

    if (!token) {
      navigate("/");
    }

  }, [navigate]);

  // =========================
  // state
  // =========================
  const [title, setTitle] = useState("");
  const [location, setLocation] = useState("");
  const [date, setDate] = useState("");
  const [category, setCategory] = useState("");
  const [storage, setStorage] = useState("");
  const [description, setDescription] = useState("");

  return (
    <Box className="create-wrapper">

      {/* ================= NAVBAR ================= */}
      <AppBar position="static" className="create-navbar">
        <Toolbar className="create-navbar-toolbar">

          <img
            src="/kw_logo.png"
            className="navbar-logo"
            alt="logo"
          />

        </Toolbar>
      </AppBar>

      {/* ================= HEADER ================= */}
      <Box className="create-header">

        <Typography variant="h4" className="create-title">
          유실물 등록
        </Typography>

        <Typography className="create-subtitle">
          유실물 정보를 입력해주세요
        </Typography>

      </Box>

      {/* ================= FORM ================= */}
      <Container maxWidth="md" className="create-container">

        <Paper className="create-paper" elevation={3}>

          {/* 제목 */}
          <TextField
            fullWidth
            label="제목"
            value={title}
            onChange={(e) => setTitle(e.target.value)}
          />

          {/* 습득 장소 */}
          <TextField
             fullWidth
              select
              label="습득 장소"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
          >
            <MenuItem value="화도관">화도관</MenuItem>
            <MenuItem value="비마관">비마관</MenuItem>
            <MenuItem value="새빛관">새빛관</MenuItem>
            <MenuItem value="참빛관">참빛관</MenuItem>
            <MenuItem value="복지관">복지관</MenuItem>
            <MenuItem value="한울관">한울관</MenuItem>
            <MenuItem value="연구관">연구관</MenuItem>
            <MenuItem value="문화관">문화관</MenuItem>
            <MenuItem value="누리관">누리관</MenuItem>
            <MenuItem value="비마관">80주년 기념관</MenuItem>
            <MenuItem value="옥의관">옥의관 경비실</MenuItem>
          </TextField>

          {/* 습득 일자 */}
          <TextField
            fullWidth
            type="date"
            InputLabelProps={{ shrink: true }}
            value={date}
            onChange={(e) => setDate(e.target.value)}
          />

          {/* 물품 분류 */}
          <TextField
            fullWidth
            select
            label="물품 분류"
            value={category}
            onChange={(e) => setCategory(e.target.value)}
          >
            <MenuItem value="노트북">노트북</MenuItem>
            <MenuItem value="태블릿">태블릿</MenuItem>
            <MenuItem value="휴대폰">휴대폰</MenuItem>
            <MenuItem value="지갑">지갑</MenuItem>
            <MenuItem value="가방">가방</MenuItem>
          </TextField>

          {/* 보관 장소 */}
          <TextField
            fullWidth
            select
            label="보관 장소"
            value={storage}
            onChange={(e) => setStorage(e.target.value)}
          >
            <MenuItem value="화도관">화도관 경비실</MenuItem>
            <MenuItem value="비마관">비마관 경비실</MenuItem>
            <MenuItem value="새빛관">새빛관 경비실</MenuItem>
            <MenuItem value="참빛관">참빛관 경비실</MenuItem>
            <MenuItem value="복지관">복지관 경비실</MenuItem>
            <MenuItem value="한울관">한울관 경비실</MenuItem>
            <MenuItem value="연구관">연구관 경비실</MenuItem>
            <MenuItem value="문화관">문화관 경비실</MenuItem>
            <MenuItem value="누리관">누리관 경비실</MenuItem>
            <MenuItem value="비마관">80주년 기념관 경비실</MenuItem>
            <MenuItem value="옥의관">옥의관 경비실</MenuItem>
          </TextField>

          {/* 상세 정보 */}
          <TextField
            fullWidth
            multiline
            rows={5}
            label="상세 정보"
            value={description}
            onChange={(e) => setDescription(e.target.value)}
          />

          {/* 버튼 */}
          <Button
            fullWidth
            variant="contained"
            className="submit-button"
          >
            게시물 등록
          </Button>

        </Paper>

      </Container>

    </Box>
  );
}

export default CreatePage;
